#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res; 
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=1e5+10,INF=0x3f3f3f3f;struct node{int l,r,mn;}t[N<<7];int Rt[N],cnt;
int head[N],des[N<<1],nxt[N<<1],cgt,RT,n,a[N],lst=0,dep[N],dfn[N],cdt,QL[N],qr[N],P[N];
inline void update(const int &x){t[x].mn=min(t[t[x].l].mn,t[t[x].r].mn);}
inline void ins(const int &x,const int &y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
inline void dfs(const int &u,const int &fa=0)
	{dep[u]=dep[fa]+1;dfn[u]=++cdt;grep(u,i)if(des[i]!=fa)dfs(des[i],u);qr[u]=cdt;}
inline void add(int cur,int &x,int pos,int w,int l=1,int r=n)
{
	t[x=++cnt]=t[cur];if(l==r){t[x].mn=w;return;} int mid=(l+r)>>1;
	pos<=mid?add(t[cur].l,t[x].l,pos,w,l,mid):add(t[cur].r,t[x].r,pos,w,mid+1,r);update(x);
}
inline int qry(int cur,int ql,int qr,int l=1,int r=n)
{
	if(ql==l&&r==qr)return t[cur].mn;int mid=(l+r)>>1;
	if(qr<=mid)return qry(t[cur].l,ql,qr,l,mid);if(ql>mid)return qry(t[cur].r,ql,qr,mid+1,r);
	return min(qry(t[cur].l,ql,mid,l,mid),qry(t[cur].r,mid+1,qr,mid+1,r));
}
int main()
{
	n=read();RT=read();rep(1,n,i)a[i]=read();
	t[0].mn=INF;rep(2,n,i)ins(read(),read());dfs(RT);
	rep(1,n,i)P[i]=i;std::sort(P+1,P+n+1,[&](const int &x,const int &y){return dep[x]<dep[y];});
	rep(1,n,i)add(Rt[i-1],Rt[i],dfn[P[i]],a[P[i]]),QL[dep[P[i]]]=i;int mxd=dep[P[n]];
//	rep(1,n,i)printf("%d ",dep[i]);puts("");
//	rep(1,n,i)printf("%d ",P[i]);puts("");
//	rep(1,n,i)printf("%d ",dfn[i]);puts("");
//	rep(1,n,i)printf("%d ",qr[i]);puts("");
	int Q=read();while(Q--)
	{
		int x=(read()+lst)%n+1,k=(read()+lst)%n;
//		printf("Qry %d %d :: ",x,k);
		printf("%d\n",lst=qry(Rt[QL[min(dep[x]+k,mxd)]],dfn[x],qr[x]));
//		printf("qry Rt[%d] %d %d\n",QL[min(dep[x]+k,mxd)],dfn[x],qr[x]);
	}
	
}
